const err = $input.first().json;
const msg = err.execution?.error?.message || 'unknown error';
const categories = [
  { pattern: /rate.?limit|429/i,      category: 'RATE_LIMIT',    retryable: true,  retryDelayMs: 60000 },
  { pattern: /timeout|ETIMEDOUT/i,    category: 'TIMEOUT',       retryable: true,  retryDelayMs: 5000  },
  { pattern: /network|ECONNREFUSED/i, category: 'NETWORK',       retryable: true,  retryDelayMs: 10000 },
  { pattern: /validation|422/i,       category: 'VALIDATION',    retryable: false, retryDelayMs: 0    },
  { pattern: /not.?found|404/i,       category: 'NOT_FOUND',     retryable: false, retryDelayMs: 0    },
  { pattern: /auth|401|403/i,         category: 'AUTH',          retryable: false, retryDelayMs: 0    },
];
const match = categories.find(c => c.pattern.test(msg));
const classified = {
  category:     match?.category    || 'UNKNOWN',
  retryable:    match?.retryable   ?? true,
  retryDelayMs: match?.retryDelay  || 5000,
  message:      msg,
  workflow:     err.workflow?.name,
  timestamp:    new Date().toISOString(),
};
console.error('[ERROR]', JSON.stringify(classified));
return [{ json: classified }];
